mapper.select:
SELECT a.id as articleId, a.title, a.short_title as shortTitle, a.summary, IFNULL(a.picture, '') as cover, a.user_id as authorId, IFNULL(ui.user_name, '匿名') as author, IFNULL(ui.user_name, '匿名') as authorName, IFNULL(ui.photo, '') as authorAvatar, a.category_id as categoryId, a.url_slug as slug, CASE a.source WHEN 1 THEN '转载' WHEN 2 THEN '原创' WHEN 3 THEN '翻译' ELSE '' END as sourceName, a.source as sourceType, a.source_url as sourceUrl, a.status, a.read_type as readType, IFNULL(rc.cnt, 0) as readCount, (SELECT COUNT(*) FROM user_foot uf WHERE uf.document_id = a.id AND uf.document_type = 1 AND uf.praise_stat = 1) as likeCount, (SELECT COUNT(*) FROM comment c WHERE c.article_id = a.id AND c.deleted = 0) as commentCount, a.create_time as createTime, a.update_time as updateTime FROM article a LEFT JOIN user_info ui ON a.user_id = ui.user_id AND ui.deleted = 0 LEFT JOIN read_count rc ON rc.document_id = a.id AND rc.document_type = 1 WHERE a.deleted = 0 AND a.status = 1
AND a.category_id = #{categoryId}
ORDER BY a.topping_stat DESC, a.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT a.id as articleId, a.title, a.short_title as shortTitle, a.summary, IFNULL(a.picture, '') as cover, a.user_id as authorId, IFNULL(ui.user_name, '匿名') as author, IFNULL(ui.user_name, '匿名') as authorName, IFNULL(ui.photo, '') as authorAvatar, a.category_id as categoryId, a.url_slug as slug, CASE a.source WHEN 1 THEN '转载' WHEN 2 THEN '原创' WHEN 3 THEN '翻译' ELSE '' END as sourceName, a.source as sourceType, a.status, a.read_type as readType, IFNULL(rc.cnt, 0) as readCount, (SELECT COUNT(*) FROM user_foot uf WHERE uf.document_id = a.id AND uf.document_type = 1 AND uf.praise_stat = 1) as likeCount, (SELECT COUNT(*) FROM comment c WHERE c.article_id = a.id AND c.deleted = 0) as commentCount, a.create_time as createTime, a.update_time as updateTime FROM article a LEFT JOIN user_info ui ON a.user_id = ui.user_id AND ui.deleted = 0 LEFT JOIN read_count rc ON rc.document_id = a.id AND rc.document_type = 1 WHERE a.deleted = 0 AND a.status = 1 AND a.topping_stat = 1
AND a.category_id = #{categoryId}
ORDER BY a.create_time DESC LIMIT #{limit}

SELECT a.id as articleId, a.title, a.short_title as shortTitle, a.summary, IFNULL(a.picture, '') as cover, a.user_id as authorId, IFNULL(ui.user_name, '匿名') as author, IFNULL(ui.user_name, '匿名') as authorName, IFNULL(ui.photo, '') as authorAvatar, a.category_id as categoryId, a.url_slug as slug, CASE a.source WHEN 1 THEN '转载' WHEN 2 THEN '原创' WHEN 3 THEN '翻译' ELSE '' END as sourceName, a.source as sourceType, a.status, a.read_type as readType, IFNULL(rc.cnt, 0) as readCount, (SELECT COUNT(*) FROM user_foot uf WHERE uf.document_id = a.id AND uf.document_type = 1 AND uf.praise_stat = 1) as likeCount, (SELECT COUNT(*) FROM comment c WHERE c.article_id = a.id AND c.deleted = 0) as commentCount, a.create_time as createTime, a.update_time as updateTime FROM article a LEFT JOIN user_info ui ON a.user_id = ui.user_id AND ui.deleted = 0 LEFT JOIN read_count rc ON rc.document_id = a.id AND rc.document_type = 1 WHERE a.deleted = 0 AND a.status = 1
AND a.create_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY)
ORDER BY a.topping_stat DESC, a.create_time DESC LIMIT #{offset}, #{pageSize}
